// Solution
#include <iostream>
#include <vector>
using namespace std;

void binary_search(int* arr, int n, int target) {
    int left = 0;
    int right = n - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) {
            return cout << mid << endl,
                       exit(0);
        } else if (arr[mid] > target) {
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return cout << -1 << endl,
           exit(0);
}

int main() {
    int n;
    cin >> n;
    int* arr = new int[n];
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    int target;
    cin >> target;
    binary_search(arr, n, target);
    delete[] arr;
    return 0;
}

