import sys

class Solution:
    def binary_search(self, arr, n, target):
        left = 0
        right = n - 1
        while left <= right:
            mid = left + (right - left) // 2
            if arr[mid] == target:
                print(mid)
                return
            elif arr[mid] > target:
                right = mid - 1
            else:
                left = mid + 1
        print(-1)

def main():
    n = int(input())
    arr = list(map(int, input().split()))
    target = int(input())
    Solution().binary_search(arr, n, target)

if __name__ == '__main__':
    main()

